#!/data/data/com.termux/files/usr/bin/env python3
import os, base64, sys

TARGET = "/storage/emulated/0/Download/3/payment-code-beautifier"
FILES = {
    "index.html": "",
    "css/style.css": "",
    "js/app.js": ""
}

print("="*50)
print("Payment Code Beautifier v2.0 - 部署")
print("="*50)

# 检查存储权限
if not os.path.exists("/storage/emulated/0/Download"):
    print("\n[!] 请先运行: termux-setup-storage")
    sys.exit(1)

print("\n[1/3] 创建目录: " + TARGET)
try:
    os.makedirs(TARGET, exist_ok=True)
    os.makedirs(os.path.join(TARGET, "css"), exist_ok=True)
    os.makedirs(os.path.join(TARGET, "js"), exist_ok=True)
    os.makedirs(os.path.join(TARGET, "images"), exist_ok=True)
    print("  ✓ 目录创建成功")
except Exception as e:
    print("  ✗ 错误: " + str(e))
    sys.exit(1)

print("\n[2/3] 写入文件...")
for fp, b64 in FILES.items():
    try:
        fullpath = os.path.join(TARGET, fp)
        with open(fullpath, "wb") as f:
            f.write(base64.b64decode(b64))
        print("  ✓ " + fp + " (" + str(len(base64.b64decode(b64))) + " bytes)")
    except Exception as e:
        print("  ✗ " + fp + " 错误: " + str(e))

print("\n[3/3] 验证文件...")
for fp in FILES.keys():
    fullpath = os.path.join(TARGET, fp)
    if os.path.exists(fullpath):
        size = os.path.getsize(fullpath)
        print("  ✓ " + fp + " 存在 (" + str(size) + " bytes)")
    else:
        print("  ✗ " + fp + " 不存在!")

print("\n" + "="*50)
print("✅ 部署完成!")
print("="*50)
print("\n📁 项目路径: " + TARGET)
print("\n📱 使用方法:")
print("   1. 文件管理器打开 /Download/3/payment-code-beautifier/")
print("   2. 点击 index.html 用浏览器打开")
print("   3. 或: cd \"" + TARGET + "\" && python3 -m http.server 8080")
print("\n📤 GitHub 推送:")
print('   cd "' + TARGET + '" && git init && git add .')
print("   git commit -m 'v2.0'")
print("   git remote add origin https://github.com/USER/REPO.git")
print("   git branch -M main && git push -u origin main")
print("="*50)
